#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve);
use Digest::SHA qw(sha256_hex);
use File::Spec;
use Fcntl qw(:flock);
use CGI;
use CGI::Cookie;

my $SESSION_DIR = '/tmp/sessions';
my $SESSION_TIMEOUT = 3600;
my $SESSION_ID_LENGTH = 32;

sub init_session_dir {
    unless (-d $SESSION_DIR) {
        mkdir $SESSION_DIR, 0700 or die "Cannot create session directory: $!";
    }
    chmod 0700, $SESSION_DIR;
}

sub generate_session_id {
    my $random = join('', map { sprintf("%02x", int(rand(256))) } 1..$SESSION_ID_LENGTH);
    my $timestamp = time();
    my $session_id = sha256_hex($random . $timestamp . $$);
    return $session_id;
}

sub validate_session_id {
    my ($session_id) = @_;
    return 0 unless defined $session_id;
    return 0 unless $session_id =~ /^[a-f0-9]{64}$/;
    return 1;
}

sub get_session_file {
    my ($session_id) = @_;
    return unless validate_session_id($session_id);
    
    my $filename = "sess_$session_id";
    $filename =~ s/[^a-f0-9_]//g;
    
    my $filepath = File::Spec->catfile($SESSION_DIR, $filename);
    my $canonical = File::Spec->canonpath($filepath);
    my $session_dir_canonical = File::Spec->canonpath($SESSION_DIR);
    
    return unless index($canonical, $session_dir_canonical) == 0;
    
    return $canonical;
}

sub create_session {
    my ($data) = @_;
    $data ||= {};
    
    init_session_dir();
    
    my $session_id = generate_session_id();
    my $session_file = get_session_file($session_id);
    
    return unless $session_file;
    
    my $session = {
        id => $session_id,
        created => time(),
        last_access => time(),
        data => $data
    };
    
    eval {
        nstore($session, $session_file);
        chmod 0600, $session_file;
    };
    
    if ($@) {
        warn "Failed to create session: $@";
        return;
    }
    
    return $session_id;
}

sub load_session {
    my ($session_id) = @_;
    
    return unless validate_session_id($session_id);
    
    my $session_file = get_session_file($session_id);
    return unless $session_file;
    return unless -f $session_file;
    
    my $session;
    eval {
        open my $fh, '<', $session_file or die "Cannot open session file: $!";
        flock($fh, LOCK_SH) or die "Cannot lock session file: $!";
        
        $session = retrieve($session_file);
        
        flock($fh, LOCK_UN);
        close $fh;
    };
    
    if ($@) {
        warn "Failed to load session: $@";
        return;
    }
    
    return unless ref($session) eq 'HASH';
    return unless $session->{id} eq $session_id;
    
    my $age = time() - $session->{last_access};
    if ($age > $SESSION_TIMEOUT) {
        destroy_session($session_id);
        return;
    }
    
    return $session;
}

sub save_session {
    my ($session) = @_;
    
    return unless ref($session) eq 'HASH';
    return unless validate_session_id($session->{id});
    
    my $session_file = get_session_file($session->{id});
    return unless $session_file;
    
    $session->{last_access} = time();
    
    eval {
        open my $fh, '>', $session_file or die "Cannot open session file: $!";
        flock($fh, LOCK_EX) or die "Cannot lock session file: $!";
        
        nstore($session, $session_file);
        
        flock($fh, LOCK_UN);
        close $fh;
        
        chmod 0600, $session_file;
    };
    
    if ($@) {
        warn "Failed to save session: $@";
        return 0;
    }
    
    return 1;
}

sub destroy_session {
    my ($session_id) = @_;
    
    return unless validate_session_id($session_id);
    
    my $session_file = get_session_file($session_id);
    return unless $session_file;
    return unless -f $session_file;
    
    unlink $session_file or warn "Failed to delete session file: $!";
    return 1;
}

sub get_session_from_cookie {
    my ($cgi) = @_;
    $cgi ||= CGI->new();
    
    my %cookies = CGI::Cookie->fetch();
    return unless exists $cookies{'session_id'};
    
    my $session_id = $cookies{'session_id'}->value;
    return unless validate_session_id($session_id);
    
    return load_session($session_id);
}

sub set_session_cookie {
    my ($cgi, $session_id) = @_;
    $cgi ||= CGI->new();
    
    return unless validate_session_id($session_id);
    
    my $cookie = CGI::Cookie->new(
        -name    => 'session_id',
        -value   => $session_id,
        -expires => '+1h',
        -path    => '/',
        -secure  => 1,
        -httponly => 1,
        -samesite => 'Strict'
    );
    
    return $cookie;
}

sub cleanup_old_sessions {
    init_session_dir();
    
    opendir(my $dh, $SESSION_DIR) or die "Cannot open session directory: $!";
    my @files = grep { /^sess_[a-f0-9]{64}$/ } readdir($dh);
    closedir($dh);
    
    my $now = time();
    my $cleaned = 0;
    
    foreach my $file (@files) {
        my $filepath = File::Spec->catfile($SESSION_DIR, $file);
        
        next unless -f $filepath;
        
        my $mtime = (stat($filepath))[9];
        if ($now - $mtime > $SESSION_TIMEOUT) {
            unlink $filepath;
            $cleaned++;
        }
    }
    
    return $cleaned;
}

